
"use client";

import { useState, useEffect, useTransition } from 'react';
import { useFieldArray, useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { useParams, useSearchParams } from 'next/navigation';
import Link from 'next/link';

import { SiteHeader } from "@/components/SiteHeader";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Separator } from "@/components/ui/separator";
import { useToast } from "@/hooks/use-toast";

import { PlusCircle, Trash2, ArrowLeft, Loader2, Edit, X, FilePlus2 } from 'lucide-react';
import { getMenusByVendorId, addMenuItem, deleteMenuItem, type MenuItem } from '@/ai/flows/menu-flow';
import { type AddMenuItemRequest, AddMenuItemRequestSchema } from '@/lib/schema/menu';

type FormData = AddMenuItemRequest;


export default function MenuAdminPage() {
  const { vendorId } = useParams() as { vendorId: string };
  const searchParams = useSearchParams();
  const vendorName = searchParams.get('name') || '店家';
  const { toast } = useToast();

  const [menu, setMenu] = useState<MenuItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isPending, startTransition] = useTransition();

  const form = useForm<FormData>({
    resolver: zodResolver(AddMenuItemRequestSchema),
    defaultValues: {
      vendorId: vendorId,
      name: "",
      price: 0,
      optionGroups: [],
    },
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "optionGroups",
  });

  const fetchMenu = async () => {
    setIsLoading(true);
    try {
      const fetchedMenu = await getMenusByVendorId(vendorId);
      setMenu(fetchedMenu);
    } catch (error) {
      console.error("讀取菜單失敗:", error);
      toast({ variant: "destructive", title: "讀取菜單失敗", description: "無法從 Google Sheet 讀取菜單。" });
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (vendorId) {
      fetchMenu();
    }
  }, [vendorId]);

  const onSubmit = (data: FormData) => {
    startTransition(async () => {
      try {
        await addMenuItem(data);
        toast({ title: "品項已新增", description: `${data.name} 已成功新增到菜單。` });
        form.reset({
          vendorId: vendorId,
          name: "",
          price: 0,
          optionGroups: [],
        });
        await fetchMenu(); // Refresh list
      } catch (error) {
         toast({ variant: "destructive", title: "新增失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };

  const handleDeleteItem = (itemId: string, itemName: string) => {
    startTransition(async () => {
      try {
        await deleteMenuItem({ id: itemId });
        toast({ title: "品項已刪除", description: `${itemName} 已從菜單移除。`});
        await fetchMenu(); // Refresh list
      } catch (error) {
        toast({ variant: "destructive", title: "刪除失敗", description: error instanceof Error ? error.message : "發生未知錯誤" });
      }
    });
  };
  
  const defaultChoice = form.watch('optionGroups');

  return (
    <div className="min-h-screen bg-background font-body text-foreground">
      <SiteHeader />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        <div className="mb-6">
            <Link href="/admin" className="flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground">
                <ArrowLeft className="h-4 w-4" />
                返回店家列表
            </Link>
        </div>
        <h1 className="font-headline text-3xl font-bold mb-2">編輯菜單：{decodeURIComponent(vendorName)}</h1>
        <p className="text-muted-foreground mb-6">管理 {decodeURIComponent(vendorName)} 的菜單品項，可一次性建立包含多種客製化選項的餐點。</p>
        
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Add/Edit Form */}
          <section>
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <FilePlus2 className="h-6 w-6" />
                  <span>新增品項</span>
                </CardTitle>
                <CardDescription>在此建立新的餐點，並可直接加入客製化選項。</CardDescription>
              </CardHeader>
              <CardContent>
                <Form {...form}>
                  <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
                    <FormField
                      control={form.control}
                      name="name"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>品項名稱</FormLabel>
                          <FormControl><Input placeholder="例如: 招牌雞腿飯" {...field} /></FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="price"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>基本價格</FormLabel>
                          <FormControl><Input type="number" {...field} onChange={e => field.onChange(parseInt(e.target.value, 10) || 0)} /></FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    
                    <Separator />
                    
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                          <h3 className="text-lg font-medium">客製化選項</h3>
                          <Button type="button" variant="outline" size="sm" onClick={() => append({ groupName: '', choices: '', priceDeltas: '', defaultChoice: '' })}>
                            <PlusCircle className="mr-2 h-4 w-4" /> 新增選項群組
                          </Button>
                      </div>
                      
                      {fields.map((field, index) => (
                        <Card key={field.id} className="p-4 bg-muted/50 relative">
                           <Button type="button" variant="ghost" size="icon" className="absolute top-2 right-2 h-6 w-6" onClick={() => remove(index)}>
                              <X className="h-4 w-4" />
                           </Button>
                          <div className="space-y-4">
                              <FormField
                                control={form.control}
                                name={`optionGroups.${index}.groupName`}
                                render={({ field }) => (
                                  <FormItem><FormLabel>選項群組 {index + 1}</FormLabel><FormControl><Input placeholder="例如: 辣度、飯量" {...field} /></FormControl><FormMessage /></FormItem>
                                )}
                              />
                              <FormField
                                control={form.control}
                                name={`optionGroups.${index}.choices`}
                                render={({ field }) => (
                                  <FormItem><FormLabel>選項 (用,分隔)</FormLabel><FormControl><Input placeholder="例如: 不辣,小辣,中辣,大辣" {...field} /></FormControl><FormMessage /></FormItem>
                                )}
                              />
                               <FormField
                                control={form.control}
                                name={`optionGroups.${index}.priceDeltas`}
                                render={({ field }) => (
                                  <FormItem><FormLabel>價格變化 (用,分隔)</FormLabel><FormControl><Input placeholder="例如: 0,0,10,10 (可留空)" {...field} /></FormControl><FormDescription>請按上方選項順序填寫，留空表示不加價。</FormDescription><FormMessage /></FormItem>
                                )}
                              />
                              
                              <FormField
                                control={form.control}
                                name={`optionGroups.${index}.defaultChoice`}
                                render={({ field }) => (
                                  <FormItem className="space-y-3">
                                    <FormLabel>預設選項</FormLabel>
                                    <FormControl>
                                      <RadioGroup onValueChange={field.onChange} defaultValue={field.value} className="flex flex-wrap gap-4">
                                        {(defaultChoice[index]?.choices || "").split(',').map(choice => choice.trim()).filter(Boolean).map(choice => (
                                          <FormItem key={choice} className="flex items-center space-x-2 space-y-0">
                                            <FormControl><RadioGroupItem value={choice} /></FormControl>
                                            <FormLabel className="font-normal">{choice}</FormLabel>
                                          </FormItem>
                                        ))}
                                      </RadioGroup>
                                    </FormControl>
                                    <FormMessage />
                                  </FormItem>
                                )}
                              />
                          </div>
                        </Card>
                      ))}
                    </div>

                    <Button type="submit" className="w-full" disabled={isPending}>
                      {isPending ? <><Loader2 className="mr-2 h-4 w-4 animate-spin" /> 新增中...</> : '確認新增'}
                    </Button>
                  </form>
                </Form>
              </CardContent>
            </Card>
          </section>
          
          {/* Menu Item List */}
          <section>
            <Card>
              <CardHeader>
                <CardTitle>現有品項</CardTitle>
                <CardDescription>管理已建立的餐點。點擊 <Edit className="inline h-4 w-4" /> 可編輯品項，或點擊 <Trash2 className="inline h-4 w-4" /> 刪除。</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {isLoading ? (
                  <div className="flex justify-center items-center py-4">
                    <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
                    <p className="ml-2 text-muted-foreground">讀取中...</p>
                  </div>
                ) : menu.length > 0 ? (
                  menu.map(item => (
                    <Card key={item.id} className="p-3">
                        <div className="flex justify-between items-start">
                           <div>
                              <p className="font-semibold">{item.name}</p>
                              <p className="text-sm text-muted-foreground">${item.price}</p>
                           </div>
                           <div className="flex items-center gap-1">
                             <Button variant="ghost" size="icon" disabled={isPending} aria-label="編輯"><Edit className="h-4 w-4" /></Button>
                             <AlertDialog>
                                 <AlertDialogTrigger asChild>
                                     <Button variant="ghost" size="icon" aria-label={`刪除 ${item.name}`} disabled={isPending}>
                                         <Trash2 className="h-4 w-4 text-destructive" />
                                     </Button>
                                 </AlertDialogTrigger>
                                 <AlertDialogContent>
                                     <AlertDialogHeader><AlertDialogTitle>確定要刪除品項嗎？</AlertDialogTitle><AlertDialogDescription>此動作將會從資料庫中永久刪除此品項及其所有選項，確定嗎？</AlertDialogDescription></AlertDialogHeader>
                                     <AlertDialogFooter><AlertDialogCancel>取消</AlertDialogCancel><AlertDialogAction onClick={() => handleDeleteItem(item.id, item.name)} disabled={isPending}>確定刪除</AlertDialogAction></AlertDialogFooter>
                                 </AlertDialogContent>
                             </AlertDialog>
                           </div>
                        </div>
                        {item.options && item.options.length > 0 && (
                            <div className="mt-2 pt-2 border-t">
                                {item.options.map(group => (
                                    <div key={group.name} className="text-xs">
                                        <span className="font-medium">{group.name}: </span>
                                        <span className="text-muted-foreground">
                                            {group.choices.map(c => `${c.name}${c.isDefault ? '(預設)' : ''}`).join(', ')}
                                        </span>
                                    </div>
                                ))}
                            </div>
                        )}
                    </Card>
                  ))
                ) : (
                  <p className="text-sm text-center text-muted-foreground py-4">這個店家還沒有任何菜單品項。</p>
                )}
              </CardContent>
            </Card>
          </section>

        </div>
      </main>
    </div>
  );
}
